import{_ as t,o as n,c as r,a2 as e}from"./chunks/framework.CHeM0PsO.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"spv/laporan-bulanan.md","filePath":"spv/laporan-bulanan.md"}'),i={name:"spv/laporan-bulanan.md"};function s(d,a,o,u,l,g){return n(),r("div",null,[...a[0]||(a[0]=[e('<h2 id="bab-5-laporan-bulanan-evaluasi-strategis" tabindex="-1">BAB 5: LAPORAN BULANAN (EVALUASI STRATEGIS) <a class="header-anchor" href="#bab-5-laporan-bulanan-evaluasi-strategis" aria-label="Permalink to &quot;BAB 5: LAPORAN BULANAN (EVALUASI STRATEGIS)&quot;">​</a></h2><p>Laporan Bulanan bersifat <strong>strategis</strong> dan menuntut Anda untuk mengevaluasi diri sendiri secara mendalam (Self-Reflection).</p><h3 id="_5-1-tab-1-ringkasan-sales" tabindex="-1">5.1 Tab 1: Ringkasan &amp; Sales <a class="header-anchor" href="#_5-1-tab-1-ringkasan-sales" aria-label="Permalink to &quot;5.1 Tab 1: Ringkasan &amp; Sales&quot;">​</a></h3><p><strong>A. Identitas &amp; Periode (Bagian Terpenting)</strong></p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Peringatan</th></tr></thead><tbody><tr><td><strong>Nama Supervisor</strong></td><td>Nama Anda</td></tr><tr><td><strong>Outlet</strong></td><td>Pilih outlet Anda</td></tr><tr><td><strong>Bulan Laporan</strong></td><td><strong>HATI-HATI!</strong> Begitu Anda memilih bulan, sistem langsung menarik semua data harian di bulan tersebut. Jika salah pilih bulan, semua angka di bawahnya akan salah</td></tr></tbody></table><p><strong>B. Metrik Penjualan (Kotak Hitam)</strong></p><p>Angka-angka ini muncul otomatis dalam desain kotak hitam elegan:</p><table tabindex="0"><thead><tr><th>Yang Muncul Otomatis</th><th>Penjelasan</th></tr></thead><tbody><tr><td><strong>Total Sales Real (Rp)</strong></td><td>Penjumlahan seluruh omset harian di bulan tersebut</td></tr><tr><td><strong>Target Sales (Rp)</strong></td><td>Diambil dari target yang Anda atur di Pengaturan Parameter</td></tr><tr><td><strong>Persentase Pencapaian</strong></td><td>Contoh: <strong>119%</strong> berarti Anda melebihi target</td></tr></tbody></table><p><strong>C. Ringkasan Eksekutif (Ketik Sendiri)</strong></p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Contoh</th></tr></thead><tbody><tr><td><strong>Pencapaian Utama Bulan Ini</strong></td><td>&quot;Berhasil melampaui target sales hingga 110%&quot;</td></tr><tr><td><strong>Masalah / Isu Utama</strong></td><td>&quot;Sering terjadi pemadaman listrik di minggu ke-2&quot;</td></tr><tr><td><strong>Kesimpulan Keseluruhan</strong></td><td>Opini Anda mengenai operasional bulan ini</td></tr></tbody></table><p><strong>D. Evaluasi Produk (4 Accordion: Minuman, Makanan, Snack, Lainnya)</strong></p><table tabindex="0"><thead><tr><th>Yang Muncul Otomatis</th><th>Yang Harus Anda Isi</th></tr></thead><tbody><tr><td><strong>Top 5 Produk</strong> (tidak bisa diedit)</td><td>—</td></tr><tr><td><strong>Bottom 3 Produk</strong> (tidak bisa diedit)</td><td><strong>Rencana untuk setiap produk mati:</strong> &quot;Bikin Bundling&quot;, &quot;Hapus dari menu&quot;, atau &quot;Tingkatkan rasa&quot;</td></tr></tbody></table><h3 id="_5-2-tab-2-staff-quality-control" tabindex="-1">5.2 Tab 2: Staff &amp; Quality Control <a class="header-anchor" href="#_5-2-tab-2-staff-quality-control" aria-label="Permalink to &quot;5.2 Tab 2: Staff &amp; Quality Control&quot;">​</a></h3><p><strong>A. Evaluasi Operasional Staf:</strong></p><table tabindex="0"><thead><tr><th>Yang Muncul Otomatis</th><th>Catatan</th></tr></thead><tbody><tr><td><strong>% Kepatuhan SOP</strong></td><td>Rata-rata dari audit mingguan (tidak bisa diubah)</td></tr><tr><td><strong>Total Telat (Kali)</strong></td><td>Berwarna merah tebal. Akumulasi sebulan penuh (tidak bisa diubah)</td></tr></tbody></table><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Catatan</th></tr></thead><tbody><tr><td><strong>SP / Teguran Keluar</strong></td><td>Berapa kali Anda mengeluarkan Surat Peringatan bulan ini</td></tr></tbody></table><p><strong>B. Turnover (Karyawan Resign):</strong></p><p>Jika ada staf yang keluar bulan ini:</p><ol><li>Tekan tombol <strong>&quot;+ Tambah Staf Resign&quot;</strong></li><li>Isi nama, alasan, dan tanggal efektif</li><li>Setiap nama muncul sebagai kartu putih dengan tombol hapus (jika salah input)</li></ol><blockquote><p><strong>Sinkronisasi Otomatis:</strong> Saat Anda mengirim laporan bulanan dengan daftar resign, sistem otomatis mengubah status staf tersebut di database utama menjadi &quot;Resign&quot;. Anda tidak perlu menghapusnya manual di Pengaturan.</p></blockquote><p><strong>C. Evaluasi Individu Staf (Sistem Hybrid AI):</strong></p><p>Di bagian ini, sistem memberikan <strong>saran awal</strong> untuk setiap staf berdasarkan rata-rata nilai mingguan:</p><table tabindex="0"><thead><tr><th>Kolom</th><th>Cara Kerja</th></tr></thead><tbody><tr><td><strong>Status Penilaian</strong></td><td>Sudah terisi otomatis oleh sistem (misal: &quot;Stagnan&quot;). Tapi Anda <strong>boleh mengubahnya</strong> jika merasa staf layak nilai lebih baik atau lebih buruk</td></tr><tr><td><strong>Catatan / Alasan</strong></td><td>Ruang bagi Anda untuk menulis &quot;rapor akhir&quot; staf tersebut</td></tr></tbody></table><p><strong>D. Rekap QC &amp; Komplain:</strong></p><table tabindex="0"><thead><tr><th>Yang Muncul Otomatis</th><th>Yang Harus Anda Isi</th></tr></thead><tbody><tr><td>Total Kasus Komplain (sebulan)</td><td>—</td></tr><tr><td>Total Remake Produk (sebulan)</td><td>—</td></tr><tr><td>—</td><td><strong>Evaluasi QC Espresso:</strong> Konsistensi rasa kopi sebulan terakhir</td></tr><tr><td>—</td><td><strong>QC Produk Lainnya:</strong> Tekan &quot;+ TAMBAH&quot; untuk menambah evaluasi per menu</td></tr></tbody></table><h3 id="_5-3-tab-3-evaluasi-rencana-strategis" tabindex="-1">5.3 Tab 3: Evaluasi &amp; Rencana Strategis <a class="header-anchor" href="#_5-3-tab-3-evaluasi-rencana-strategis" aria-label="Permalink to &quot;5.3 Tab 3: Evaluasi &amp; Rencana Strategis&quot;">​</a></h3><p><strong>A. Fasilitas &amp; Inventaris:</strong></p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Catatan</th></tr></thead><tbody><tr><td><strong>Total Pengeluaran Perbaikan (Rp)</strong></td><td>Uang yang habis untuk servis alat bulan ini</td></tr><tr><td><strong>Kerusakan Belum Selesai</strong></td><td>Laporan alat yang masih rusak dan butuh tindakan</td></tr></tbody></table><p><strong>B. Strategi Bulan Depan:</strong></p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Catatan</th></tr></thead><tbody><tr><td><strong>Fokus &amp; Strategi Utama</strong></td><td>Janji Anda untuk bulan depan</td></tr><tr><td><strong>Kebutuhan Supervisor</strong></td><td>Dukungan yang dibutuhkan dari owner</td></tr></tbody></table><p><strong>C. Evaluasi Mandiri (Paling Pribadi):</strong></p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Catatan</th></tr></thead><tbody><tr><td><strong>Pencapaian Terbaik Pribadi</strong></td><td>Apa yang Anda banggakan bulan ini</td></tr><tr><td><strong>Tantangan Tersulit</strong></td><td>Pengakuan jujur tentang kelemahan Anda</td></tr><tr><td><strong>Skill Yang Ingin Ditingkatkan</strong></td><td>Area kemampuan yang ingin diasah</td></tr><tr><td><strong>Rating Kinerja Sendiri (1-10)</strong></td><td>Geser slider untuk merating diri sendiri</td></tr></tbody></table><hr>',33)])])}const p=t(i,[["render",s]]);export{h as __pageData,p as default};
